import { Component, OnInit, inject, signal } from '@angular/core';
import { ElementsService } from '../../services/elements.service';
import { Element } from '../../models/element';

@Component({
  selector: 'app-elements-table',
  imports: [],
  templateUrl: './elements-table.component.html',
  styleUrl: './elements-table.component.css'
})
export class ElementsTableComponent implements OnInit {
  private readonly elementsService = inject(ElementsService);

  readonly elements = signal<Element[]>([]);
  readonly isLoading = signal<boolean>(false);
  readonly errorMessage = signal<string | null>(null);

  ngOnInit(): void {
    this.loadElements();
  }

  loadElements(): void {
    this.isLoading.set(true);
    this.errorMessage.set(null);

    this.elementsService.getElements().subscribe({
      next: (data) => {
        if (!Array.isArray(data)) {
          this.errorMessage.set('La respuesta del servidor no es una lista válida.');
          this.elements.set([]);
          this.isLoading.set(false);
          return;
        }

        for (const item of data) {
          if (!item || typeof item.id !== 'number' || !item.name || !item.alias || !item.description || !item.category) {
            this.errorMessage.set('Los datos recibidos del servidor no tienen el formato esperado.');
            this.elements.set([]);
            this.isLoading.set(false);
            return;
          }
        }

        this.elements.set(data);
        this.isLoading.set(false);
      },
      error: (err) => {
        console.error('Error fetching elements:', err);
        this.errorMessage.set('No se pudo conectar con el servidor de la API o el endpoint no respondió.');
        this.elements.set([]);
        this.isLoading.set(false);
      }
    });
  }
}

