}

.badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-weight: 700;
  font-size: 0.75rem;
  letter-spacing: 0.025em;
  padding: 0.35rem 0.75rem;
  border-radius: 0.5rem;
